 1→-- Enrich crm_* tables with additional columns for the full CRM type model.
 2→-- Owned by: moltis-crm crate
 3→--
 4→-- This migration runs after 20260317000000_init.sql which created the base
 5→-- crm_contacts, crm_matters, crm_interactions, and crm_contact_channels tables.
 6→-- SQLite supports ADD COLUMN and RENAME COLUMN (≥3.25.0) but not DROP COLUMN
 7→-- in older versions; new columns use nullable or DEFAULT-bearing types.
 8→
 9→-- ── crm_contacts: add PII and stage columns ───────────────────────────────────
10→ALTER TABLE crm_contacts ADD COLUMN email TEXT;
11→ALTER TABLE crm_contacts ADD COLUMN phone TEXT;
12→ALTER TABLE crm_contacts ADD COLUMN stage TEXT NOT NULL DEFAULT 'lead';
13→
14→-- ── crm_contact_channels: rename identifier field, add display_name + updated_at ─
15→-- channel_identifier → channel_id (aligns with domain type field name)
16→ALTER TABLE crm_contact_channels RENAME COLUMN channel_identifier TO channel_id;
17→ALTER TABLE crm_contact_channels ADD COLUMN display_name TEXT;
18→ALTER TABLE crm_contact_channels ADD COLUMN updated_at INTEGER NOT NULL DEFAULT 0;
19→
20→-- Rebuild unique index with new column name.
21→DROP INDEX IF EXISTS idx_crm_contact_channels_contact_id;
22→CREATE INDEX IF NOT EXISTS idx_crm_contact_channels_contact_id
23→    ON crm_contact_channels(contact_id);
24→
25→-- The UNIQUE(channel_type, channel_identifier) constraint was declared inline on
26→-- the table; SQLite preserves it through RENAME COLUMN automatically.
27→
28→-- ── crm_matters: add description, phase, practice_area ────────────────────────
29→ALTER TABLE crm_matters ADD COLUMN description TEXT;
30→ALTER TABLE crm_matters ADD COLUMN phase         TEXT NOT NULL DEFAULT 'intake';
31→ALTER TABLE crm_matters ADD COLUMN practice_area TEXT NOT NULL DEFAULT 'other';
32→
33→-- ── crm_interactions: rename body → summary, add channel + updated_at ─────────
34→ALTER TABLE crm_interactions RENAME COLUMN body TO summary;
35→ALTER TABLE crm_interactions ADD COLUMN channel    TEXT;
36→ALTER TABLE crm_interactions ADD COLUMN updated_at INTEGER NOT NULL DEFAULT 0;
37→
38→-- Rebuild interaction indexes after schema change.
39→DROP INDEX IF EXISTS idx_crm_interactions_contact_id;
40→DROP INDEX IF EXISTS idx_crm_interactions_matter_id;
41→DROP INDEX IF EXISTS idx_crm_interactions_created_at;
42→
43→CREATE INDEX IF NOT EXISTS idx_crm_interactions_contact_id
44→    ON crm_interactions(contact_id);
45→
46→CREATE INDEX IF NOT EXISTS idx_crm_interactions_matter_id
47→    ON crm_interactions(matter_id)
48→    WHERE matter_id IS NOT NULL;
49→
50→CREATE INDEX IF NOT EXISTS idx_crm_interactions_updated_at
51→    ON crm_interactions(updated_at DESC);
52→

