 1→use std::error::Error as StdError;
 2→
 3→#[derive(Debug, thiserror::Error)]
 4→pub enum Error {
 5→    #[error(transparent)]
 6→    Sqlx(#[from] sqlx::Error),
 7→    #[error(transparent)]
 8→    Migration(#[from] sqlx::migrate::MigrateError),
 9→    #[error(transparent)]
10→    Json(#[from] serde_json::Error),
11→    #[error("record not found: {id}")]
12→    NotFound { id: String },
13→    #[error("invalid value for {field}: {value:?}")]
14→    Parse { field: &'static str, value: String },
15→    #[error("{context}: {source}")]
16→    External {
17→        context: String,
18→        #[source]
19→        source: Box<dyn StdError + Send + Sync>,
20→    },
21→}
22→
23→impl Error {
24→    #[must_use]
25→    pub fn not_found(id: impl Into<String>) -> Self {
26→        Self::NotFound { id: id.into() }
27→    }
28→
29→    #[must_use]
30→    pub fn parse(field: &'static str, value: impl Into<String>) -> Self {
31→        Self::Parse {
32→            field,
33→            value: value.into(),
34→        }
35→    }
36→
37→    #[must_use]
38→    pub fn external<E>(context: impl Into<String>, source: E) -> Self
39→    where
40→        E: StdError + Send + Sync + 'static,
41→    {
42→        Self::External {
43→            context: context.into(),
44→            source: Box::new(source),
45→        }
46→    }
47→}
48→
49→pub type Result<T> = std::result::Result<T, Error>;
