1007→fn check_semantic_warnings(config: &MoltisConfig, diagnostics: &mut Vec<Diagnostic>) {
1008→    let is_localhost = config.server.bind == "127.0.0.1"
1009→        || config.server.bind == "localhost"
1010→        || config.server.bind == "::1";
1011→
1012→    // auth.disabled + non-localhost
1013→    if config.auth.disabled && !is_localhost {
1014→        diagnostics.push(Diagnostic {
1015→            severity: Severity::Warning,
1016→            category: "security",
1017→            path: "auth".into(),
1018→            message: format!(
1019→                "authentication is disabled while binding to {}",
1020→                config.server.bind
1021→            ),
1022→        });
1023→    }
1024→
1025→    // TLS disabled + non-localhost
1026→    if !config.tls.enabled && !is_localhost {
1027→        diagnostics.push(Diagnostic {
1028→            severity: Severity::Warning,
1029→            category: "security",
1030→            path: "tls".into(),
1031→            message: format!("TLS is disabled while binding to {}", config.server.bind),
1032→        });
1033→    }
1034→
1035→    // TLS cert without key or vice versa
1036→    let has_cert = config.tls.cert_path.is_some();
1037→    let has_key = config.tls.key_path.is_some();
1038→    if has_cert && !has_key {
1039→        diagnostics.push(Diagnostic {
1040→            severity: Severity::Error,
1041→            category: "security",
1042→            path: "tls".into(),
1043→            message: "tls.cert_path is set but tls.key_path is missing".into(),
1044→        });
1045→    }
1046→    if has_key && !has_cert {
1047→        diagnostics.push(Diagnostic {
1048→            severity: Severity::Error,
1049→            category: "security",
1050→            path: "tls".into(),
1051→            message: "tls.key_path is set but tls.cert_path is missing".into(),
1052→        });
1053→    }
1054→
1055→    // Sandbox mode off
1056→    if config.tools.exec.sandbox.mode == "off" {
1057→        diagnostics.push(Diagnostic {
1058→            severity: Severity::Warning,
1059→            category: "security",
1060→            path: "tools.exec.sandbox.mode".into(),
1061→            message: "sandbox mode is disabled — commands run without isolation".into(),
1062→        });
1063→    }
