            .diagnostics
            .iter()
            .find(|d| d.path == "channels.offered[1]" && d.category == "unknown-field");
        assert!(
            warning.is_none(),
            "slack should be accepted, got: {:?}",
            result.diagnostics
        );
    }

    #[test]
    fn channels_offered_dynamic_type_accepted() {
        let toml = r#"
[channels]
offered = ["telegram", "slack"]

