"#;
        let result = validate_toml_str(toml);
        let error = result.diagnostics.iter().find(|d| {
            d.path.starts_with("channels.slack")
                && (d.severity == Severity::Error || d.category == "unknown-field")
        });
        assert!(
            error.is_none(),
